    }));

    document.getElementById("btn-premarket").addEventListener("click", () => withBtn("btn-premarket", async () => {
      const r = await fetch(BASE + "/premarket", { method: "POST", headers: { "Content-Type": "application/json" }, body: "{}" });
      const d = await r.json();
      toast(d.started ? "Pre-market scan started." : JSON.stringify(d).slice(0, 150));
    }));

    document.getElementById("btn-eod").addEventListener("click", () => withBtn("btn-eod", async () => {
      const r = await fetch(BASE + "/agent/autonomous/eod-update", { method: "POST", headers: { "Content-Type": "application/json" }, body: "{}" });
      const d = await r.json();
      toast(d.updated
        ? (d.new_high ? "New high! Floor: $" + d.eod_threshold : "Floor: $" + d.eod_threshold + " | Balance: $" + d.closing_balance)
        : JSON.stringify(d).slice(0, 150)
      , 5000);
    }));

    document.getElementById("btn-shift").addEventListener("click", () => withBtn("btn-shift", async () => {
      const r = await fetch(BASE + "/agent/income/income-summary");
      const d = await r.json();
      toast(JSON.stringify(d).slice(0, 250), 5000);
    }));

    document.getElementById("btn-luke").addEventListener("click", () => withBtn("btn-luke", async () => {
      const r = await fetch(BASE + "/agent/health/luke-status");
      const d = await r.json();
      toast((d.assessment || d.reply || JSON.stringify(d)).slice(0, 250), 6000);
    }));

    // ── LOOK ──────────────────────────────────────────────

    document.getElementById("look-btn").addEventListener("click", () => look());

    // ── STAGED TRADE ──────────────────────────────────────

    const pendingTrade = document.getElementById("pending-trade");
    const executeBtn   = document.getElementById("execute-btn");
    const skipBtn      = document.getElementById("skip-btn");
    let countdownInterval = null;

    function showPending(data) {
      const s = data.signal;
      const ticker = s.ticker || "MNQ";
      document.getElementById("pt-signal").textContent =
        s.direction + " " + ticker + "  ·  E:" + s.entry + "  S:" + s.stop + "  T:" + s.target;
      document.getElementById("pt-meta").textContent   = "Risk: $" + data.risk_dollars + "  ·  R:R " + data.rr + ":1";
      document.getElementById("pt-reason").textContent = s.reason || "";
      document.getElementById("lbl-target").textContent = "T " + s.target;
      document.getElementById("lbl-entry").textContent  = "E " + s.entry;
      document.getElementById("lbl-stop").textContent   = "S " + s.stop;
      pendingTrade.classList.add("visible");
      loadTVWidget(ticker);
      startCountdown(data.seconds_left);
    }

    function hidePending() {
      pendingTrade.classList.remove("visible");
      if (countdownInterval) { clearInterval(countdownInterval); countdownInterval = null; }
      document.getElementById("pt-chart-inner").innerHTML = "";
    }

    function loadTVWidget(ticker) {
      const container = document.getElementById("pt-chart-inner");
      container.innerHTML = "";
      const wrapper = document.createElement("div");
      wrapper.className = "tradingview-widget-container";
      const inner = document.createElement("div");
      inner.className = "tradingview-widget-container__widget";
      wrapper.appendChild(inner);
      const script = document.createElement("script");
      script.type = "text/javascript";
      script.src = "https://s3.tradingview.com/external-embedding/embed-widget-advanced-chart.js";
      script.async = true;
      script.text = JSON.stringify({
        autosize: false, width: "100%", height: 162,
        symbol: ticker === "MES" ? "CME_MINI:MES1!" : "CME_MINI:MNQ1!",
        interval: "5", timezone: "America/New_York", theme: "dark", style: "1", locale: "en",
        hide_top_toolbar: true, hide_legend: true, allow_symbol_change: false,
        calendar: false, hide_volume: true, support_host: "https://www.tradingview.com"
      });
      wrapper.appendChild(script);
      container.appendChild(wrapper);
    }

    function startCountdown(seconds) {
      if (countdownInterval) clearInterval(countdownInterval);
      const total = 300;
      let s = seconds;
      const textEl = document.getElementById("pt-countdown-text");
      const ringEl = document.getElementById("pt-ring");
      function tick() {
        if (s <= 0) { hidePending(); return; }
        textEl.textContent = Math.floor(s / 60) + ":" + (s % 60).toString().padStart(2, "0");
        ringEl.style.strokeDasharray = ((s / total) * 100) + " 100";
        ringEl.style.stroke = s < 60 ? "#f87171" : "#e2b96a";
        s--;
      }
      tick();
      countdownInterval = setInterval(tick, 1000);
    }

    async function checkPendingSignal() {
      try {
        const r = await fetch(BASE + "/agent/autonomous/pending");
        const d = await r.json();
        if (d.pending) showPending(d);
        else hidePending();
      } catch {}
    }
    checkPendingSignal();
    setInterval(checkPendingSignal, 15000);

    executeBtn.addEventListener("click", async () => {
      executeBtn.disabled = true; executeBtn.textContent = "...";
      try {
        const r = await fetch(BASE + "/agent/autonomous/execute-staged", { method: "POST", headers: { "Content-Type": "application/json" }, body: "{}" });
        const d = await r.json();
        hidePending();
        if (d.executed === false) addMessage("assistant", "Execute failed: " + d.reason, "alert");
      } catch { addMessage("assistant", "Execute error.", "alert"); }
      executeBtn.disabled = false; executeBtn.textContent = "EXECUTE";
    });

    skipBtn.addEventListener("click", async () => {
      try { await fetch(BASE + "/agent/autonomous/skip-staged", { method: "POST", headers: { "Content-Type": "application/json" }, body: "{}" }); } catch {}
      hidePending();
    });

    document.addEventListener("keydown", e => {
      if (!pendingTrade.classList.contains("visible")) return;
      if ((e.key === "e" || e.key === "E") && !executeBtn.disabled) executeBtn.click();
      if (e.key === "s" || e.key === "S") skipBtn.click();
    });

    // ── WEBSOCKET ─────────────────────────────────────────

    ws.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data);
        if (data.type === "staged_trade")   showPending(data);
        else if (data.type === "status_update") updateChips(data);
        else if (data.type === "notification") {
          addMessage("assistant", data.message, "alert");
          if (/02B|KILL|PAPER|LIVE|CLOSED/.test(data.message)) syncStatus();
        }
      } catch {}
    };

    // ── STATE INDICATOR ───────────────────────────────────

    function updateStateIndicator(state) {
      if (!state) return;
      const el = document.getElementById("ribbon-state");
      el.className = state === "regulated" ? "" : state;
      const labels = { regulated: "ONLINE", stressed: "STRESSED", spiraling: "SPIRALING", rule_break: "RULE BREAK" };
      el.textContent = labels[state] || "ONLINE";
    }

    // ── MESSAGES ─────────────────────────────────────────

    function addMessage(role, text, type) {
      const wrapper = document.createElement("div");
      wrapper.className = "wrapper " + (role === "user" ? "user" : "jarvis");
      if (role !== "user") {
        const label = document.createElement("div");
        label.className = "label";
        label.textContent = type === "vision" ? "JARVIS — VISION" : type === "alert" ? "JARVIS — ALERT" : "JARVIS";
        wrapper.appendChild(label);
      }
      const msg = document.createElement("div");
      msg.className = "msg " + (role === "user" ? "user" : type === "vision" ? "vision" : type === "alert" ? "alert" : "jarvis");
      msg.textContent = text;
      wrapper.appendChild(msg);
      messages.appendChild(wrapper);
      messages.scrollTop = messages.scrollHeight;
    }

    function addImageMessage(dataUrl) {
      const wrapper = document.createElement("div");
      wrapper.className = "wrapper user";
      const msg = document.createElement("div");
      msg.className = "msg user";
      const img = document.createElement("img");
      img.src = dataUrl;
      msg.appendChild(img);
      wrapper.appendChild(msg);
      messages.appendChild(wrapper);
      messages.scrollTop = messages.scrollHeight;
    }

    function showThinking(text) {
      const div = document.createElement("div");
      div.className = "thinking"; div.id = "thinking";
      div.textContent = text || "THINKING...";
      messages.appendChild(div);
      messages.scrollTop = messages.scrollHeight;
    }

    function hideThinking() {
      const t = document.getElementById("thinking");
      if (t) t.remove();
    }

    // ── IMAGE PASTE / DROP ────────────────────────────────

    async function handleImageBlob(blob, mimeType) {
      const reader = new FileReader();
      reader.onload = async (evt) => {
        const dataUrl = evt.target.result;
        const base64  = dataUrl.split(",")[1];
        addImageMessage(dataUrl);
        const question = input.value.trim() || "What's in this image?";
        input.value = "";
        showThinking("ANALYZING...");
        sendBtn.disabled = true;
        try {
          const r = await fetch(BASE + "/see-image", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ image: base64, mime_type: mimeType, question })
          });
          const d = await r.json();
          hideThinking();
          addMessage("assistant", d.reply || d.error || "No response.", "vision");
        } catch {
          hideThinking();
          addMessage("assistant", "Image analysis failed.");
        }
        sendBtn.disabled = false;
        input.focus();
      };
      reader.readAsDataURL(blob);
    }

    document.addEventListener("paste", (e) => {
      const items = Array.from(e.clipboardData?.items || []);
      const imageItem = items.find(item => item.type.startsWith("image/"));
      if (!imageItem) return;
      e.preventDefault();
      handleImageBlob(imageItem.getAsFile(), imageItem.type);
    });

    let dragDepth = 0;
    const dragOverlay = document.getElementById("drag-overlay");
    document.addEventListener("dragenter", (e) => {
      if (Array.from(e.dataTransfer?.items || []).some(i => i.kind === "file" && i.type.startsWith("image/"))) {
        dragDepth++;
        dragOverlay.classList.add("show");
      }
    });
    document.addEventListener("dragleave", () => {
      dragDepth--;
      if (dragDepth <= 0) { dragDepth = 0; dragOverlay.classList.remove("show"); }
    });
    document.addEventListener("dragover", (e) => e.preventDefault());
    document.addEventListener("drop", (e) => {
      e.preventDefault();
      dragDepth = 0;
      dragOverlay.classList.remove("show");
      const file = e.dataTransfer?.files[0];
      if (file && file.type.startsWith("image/")) handleImageBlob(file, file.type);
    });

    // ── CHAT ─────────────────────────────────────────────

    async function look(question) {
      showThinking("LOOKING...");
      sendBtn.disabled = true;
      try {
        const r = await fetch(BASE + "/see", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ question: question || "What's on this screen? Be brief." }) });
        const d = await r.json();
        hideThinking();
        addMessage("assistant", d.reply, "vision");
      } catch {
        hideThinking();
        addMessage("assistant", "Vision error.");
      }
      sendBtn.disabled = false;
      input.focus();
    }

    async function doAction(text) {
      showThinking("DOING...");
      sendBtn.disabled = true;
      const parts = text.split(" ");
      try {
        const r = await fetch(BASE + "/do", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ action: parts[0].toLowerCase(), value: parts.slice(1).join(" ") }) });
        const d = await r.json();
        hideThinking();
        addMessage("assistant", d.reply || "Done.", "vision");
      } catch {
        hideThinking();
        addMessage("assistant", "Action error.");
      }
      sendBtn.disabled = false;
      input.focus();
    }

    async function chat(text) {
      showThinking("THINKING...");
      sendBtn.disabled = true;
      try {
        const r = await fetch(BASE + "/chat", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ message: text, history }) });
        const d = await r.json();
        hideThinking();
        addMessage("assistant", d.reply);
        if (d.state) updateStateIndicator(d.state);
        history = d.history;
      } catch {
        hideThinking();
        addMessage("assistant", "Connection error.");
      }
      sendBtn.disabled = false;
      input.focus();
    }

    async function send() {
      const text = input.value.trim();
      if (!text) return;
      input.value = "";
      addMessage("user", text);
      if (/^(open|type|click|scroll|press)\s/i.test(text))      await doAction(text);
      else if (/(screen|look|what's open|what do you see)/i.test(text)) await look(text);
      else await chat(text);
    }

    sendBtn.addEventListener("click", send);
    input.addEventListener("keydown", e => { if (e.key === "Enter") send(); });
  </script>
</body>
</html>

