      border: 2px dashed #60a5fa;
      pointer-events: none;
    }
    #drag-overlay.show { display: flex; }
  </style>
</head>
<body>

  <!-- 1. Chips row -->
  <div id="chips">
    <span id="chip-mode" class="chip off">OFF</span>
    <span id="chip-pnl"  class="chip">P&L —</span>
    <span id="chip-pos"  class="chip flat">flat</span>
    <span id="chip-apex" class="chip" style="display:none"></span>
    <span id="chip-arch"  class="chip" style="display:none">ARCH:0</span>
    <span id="chip-sweep" class="chip" style="display:none">SWEEP:0</span>
    <button id="kill-day-btn"  class="kill-btn">KILL:D</button>
    <button id="kill-week-btn" class="kill-btn">KILL:W</button>
    <button id="look-btn">LOOK</button>
  </div>

  <!-- 2. Action row -->
  <div id="actions">
    <button id="btn-mkt">MKT</button>
    <button id="btn-audit">AUDIT</button>
    <button id="btn-replay">REPLAY</button>
    <button id="btn-sienna">SIENNA</button>
    <button id="btn-premarket">PRE-MKT</button>
    <button id="btn-eod">EOD</button>
    <button id="btn-shift">SHIFT</button>
    <button id="btn-luke">LUKE</button>
  </div>

  <!-- 3. Today ribbon -->
  <div id="ribbon">
    <span id="ribbon-move">MOVE: —</span>
    <span class="rsep">·</span>
    <span id="ribbon-luke">LUKE: —</span>
    <span class="rsep">·</span>
    <span id="ribbon-wtd">WTD: —</span>
    <span id="ribbon-state">ONLINE</span>
  </div>

  <!-- 4. Messages -->
  <div id="messages"></div>

  <!-- 5. Input -->
  <div id="input-area">
    <input id="input" type="text" placeholder="..." autocomplete="off" />
    <button id="send">SEND</button>
  </div>

  <!-- Staged trade overlay -->
  <div id="pending-trade">
    <div id="pt-chart">
      <div id="pt-chart-inner"></div>
      <div id="pt-price-labels">
        <span class="price-label target" id="lbl-target"></span>
        <span class="price-label entry"  id="lbl-entry"></span>
        <span class="price-label stop"   id="lbl-stop"></span>
      </div>
    </div>
    <div id="pt-body">
      <div>
        <div id="pt-header-row">
          <div class="pt-label">⚡ 02B SIGNAL — CONFIRM</div>
          <svg class="countdown-svg" viewBox="0 0 36 36">
            <circle class="ring-bg"       cx="18" cy="18" r="15.9155"/>
            <circle class="ring-progress" cx="18" cy="18" r="15.9155" id="pt-ring"/>
            <text class="ring-text" x="18" y="18" id="pt-countdown-text">5:00</text>
          </svg>
        </div>
        <div id="pt-signal"></div>
        <div id="pt-meta"></div>
        <div id="pt-reason"></div>
      </div>
      <div id="pt-actions">
        <button id="execute-btn">EXECUTE</button>
        <button id="skip-btn">SKIP</button>
      </div>
    </div>
  </div>

  <!-- Toast -->
  <div id="toast"></div>

  <!-- Drag overlay -->
  <div id="drag-overlay">DROP IMAGE</div>

  <script>
    const BASE = window.location.origin.startsWith("http") ? window.location.origin : "http://localhost:3000";
    const wsProtocol = window.location.protocol === "https:" ? "wss:" : "ws:";
    const wsHost = window.location.host || "localhost:3000";
    const ws = new WebSocket(wsProtocol + "//" + wsHost);

    const messages = document.getElementById("messages");
    const input    = document.getElementById("input");
    const sendBtn  = document.getElementById("send");
    let history = [];
    let intradayActive = false;
    let toastTimer = null;

    // ── TOAST ─────────────────────────────────────────────

    function toast(text, ms = 3500) {
      const el = document.getElementById("toast");
      el.textContent = String(text).slice(0, 300);
      el.classList.add("show");
      clearTimeout(toastTimer);
      toastTimer = setTimeout(() => el.classList.remove("show"), ms);
    }

    // ── RIBBON ────────────────────────────────────────────

    function nextLukeDose() {
      const now = new Date();
      const mins = now.getHours() * 60 + now.getMinutes();
      if (mins < 240) return "4:00AM";
      if (mins < 270) return "4:30AM";
      const mUntil = 1440 - mins + 240;
      return "4AM +" + Math.floor(mUntil / 60) + "h";
    }

    async function syncRibbon() {
      document.getElementById("ribbon-luke").textContent = "LUKE: " + nextLukeDose();
      try {
        const r = await fetch(BASE + "/agent/finance/fund-status");
        const d = await r.json();
        const bal = typeof d.balance === "number" ? d.balance.toFixed(0) : (d.balance || "—");
        document.getElementById("ribbon-move").textContent = "MOVE: $" + bal + "/$6k";
      } catch {}
      try {
        const r = await fetch(BASE + "/agent/income/income-summary");
        const d = await r.json();
        const wtd = d.week_total ?? d.weekly_income ?? d.wtd ?? null;
        document.getElementById("ribbon-wtd").textContent =
          "WTD: " + (wtd !== null ? "$" + (typeof wtd === "number" ? wtd.toFixed(0) : wtd) : "—");
      } catch {}
    }

    syncRibbon();
    setInterval(syncRibbon, 5 * 60 * 1000);

    // ── STATUS CHIPS ──────────────────────────────────────

    async function syncStatus() {
      try {
        const r = await fetch(BASE + "/agent/autonomous/status");
        updateChips(await r.json());
      } catch {}
      try {
        const r = await fetch(BASE + "/agent/architect/status");
        const d = await r.json();
        const chip = document.getElementById("chip-arch");
        chip.textContent = "ARCH:" + (d.last_observations || 0);
        chip.style.display = "";
        chip.style.color = d.zero_streak >= 3 ? "#f87171" : "";
      } catch {}
      try {
        const r = await fetch(BASE + "/agent/sweeper/status");
        const d = await r.json();
        const chip = document.getElementById("chip-sweep");
        const n = d.open_sweep_proposals || 0;
        chip.textContent = "SWEEP:" + n;
        chip.style.display = n > 0 || d.inventory_done ? "" : "none";
      } catch {}
    }

    function updateChips(data) {
      const modeChip = document.getElementById("chip-mode");
      if (data.running) {
        modeChip.textContent = data.mode === "live" ? "LIVE" : "PAPER";
        modeChip.className = "chip " + (data.mode === "live" ? "live" : "paper");
      } else {
        modeChip.textContent = "OFF";
        modeChip.className = "chip off";
      }

      const pnl = data.daily_pnl || 0;
      const pnlChip = document.getElementById("chip-pnl");
      pnlChip.textContent = (pnl >= 0 ? "+" : "") + "$" + Math.abs(pnl).toFixed(0);
      pnlChip.className = "chip" + (pnl >= 0 ? " pos" : " neg");

      const posChip = document.getElementById("chip-pos");
      if (data.open_position) {
        const p = data.open_position;
        posChip.textContent = p.ticker + " " + p.direction[0] + (p.size || 1) + "@" + p.entry;
        posChip.className = "chip";
      } else {
        posChip.textContent = "flat";
        posChip.className = "chip flat";
      }

      const apexChip = document.getElementById("chip-apex");
      if (data.apex && data.apex.enabled) {
        apexChip.textContent = "APEX " + data.apex.pct_to_target;
        apexChip.style.display = "";
      } else {
        apexChip.style.display = "none";
      }
    }

    document.getElementById("chip-mode").addEventListener("click", async () => {
      const modeChip = document.getElementById("chip-mode");
      if (modeChip.classList.contains("off")) {
        modeChip.textContent = "...";
        try {
          const sr = await fetch(BASE + "/agent/autonomous/start", { method: "POST", headers: { "Content-Type": "application/json" }, body: "{}" });
          const sd = await sr.json();
          if (sd.started === false) { addMessage("assistant", "02B blocked: " + sd.reason); await syncStatus(); return; }
          await fetch(BASE + "/agent/autonomous/launch", { method: "POST", headers: { "Content-Type": "application/json" }, body: "{}" });
          addMessage("assistant", "02B running in PAPER mode.");
        } catch { addMessage("assistant", "02B failed to start."); }
      } else {
        try {
          await fetch(BASE + "/agent/autonomous/stop", { method: "POST", headers: { "Content-Type": "application/json" }, body: "{}" });
          addMessage("assistant", "02B stopped.");
        } catch {}
      }
      await syncStatus();
    });

    document.getElementById("kill-day-btn").addEventListener("click", async () => {
      try {
        await fetch(BASE + "/agent/autonomous/kill", { method: "POST", headers: { "Content-Type": "application/json" }, body: "{}" });
        addMessage("assistant", "Daily kill activated.", "alert");
        await syncStatus();
      } catch {}
    });

    document.getElementById("kill-week-btn").addEventListener("click", async () => {
      try {
        await fetch(BASE + "/agent/autonomous/kill-week", { method: "POST", headers: { "Content-Type": "application/json" }, body: "{}" });
        addMessage("assistant", "Weekly kill activated.", "alert");
        await syncStatus();
      } catch {}
    });

    syncStatus();
    setInterval(syncStatus, 30000);

    // ── ACTION ROW ────────────────────────────────────────

    async function withBtn(btnId, fn) {
      const btn = document.getElementById(btnId);
      btn.disabled = true;
      try { await fn(btn); } catch (e) { toast("Error: " + e.message); }
      btn.disabled = false;
    }

    document.getElementById("btn-mkt").addEventListener("click", () => withBtn("btn-mkt", async (btn) => {
      if (!intradayActive) {
        const r = await fetch(BASE + "/intraday/start", { method: "POST", headers: { "Content-Type": "application/json" }, body: "{}" });
        const d = await r.json();
        if (d.started) { intradayActive = true; btn.classList.add("active"); toast("Intraday started."); }
      } else {
        await fetch(BASE + "/intraday/stop", { method: "POST", headers: { "Content-Type": "application/json" }, body: "{}" });
        intradayActive = false; btn.classList.remove("active"); toast("Intraday stopped.");
      }
    }));

    document.getElementById("btn-audit").addEventListener("click", () => withBtn("btn-audit", async () => {
      const r = await fetch(BASE + "/agent/autonomous/status");
      const d = await r.json();
      toast(
        "02B: " + (d.running ? d.mode.toUpperCase() : "OFF") +
        " | P&L: $" + (d.daily_pnl || 0).toFixed(0) +
        " | Trades: " + (d.paper_trades || 0) + "/25" +
        (d.open_position ? "\nOpen: " + d.open_position.direction + " " + d.open_position.ticker + " @" + d.open_position.entry : "\nFlat")
      , 5000);
      updateChips(d);
    }));

    document.getElementById("btn-replay").addEventListener("click", () => withBtn("btn-replay", async () => {
      const r = await fetch(BASE + "/agent/trader/assess");
      const d = await r.json();
      toast((d.assessment || JSON.stringify(d)).slice(0, 250), 6000);
    }));

    document.getElementById("btn-sienna").addEventListener("click", () => withBtn("btn-sienna", async () => {
      const r = await fetch(BASE + "/agent/sienna/model");
      const d = await r.json();
      toast(JSON.stringify(d).slice(0, 250), 5000);
    }));

    document.getElementById("btn-premarket").addEventListener("click", () => withBtn("btn-premarket", async () => {
      const r = await fetch(BASE + "/premarket", { method: "POST", headers: { "Content-Type": "application/json" }, body: "{}" });
      const d = await r.json();
      toast(d.started ? "Pre-market scan started." : JSON.stringify(d).slice(0, 150));
    }));

    document.getElementById("btn-eod").addEventListener("click", () => withBtn("btn-eod", async () => {
      const r = await fetch(BASE + "/agent/autonomous/eod-update", { method: "POST", headers: { "Content-Type": "application/json" }, body: "{}" });
      const d = await r.json();
      toast(d.updated
        ? (d.new_high ? "New high! Floor: $" + d.eod_threshold : "Floor: $" + d.eod_threshold + " | Balance: $" + d.closing_balance)
        : JSON.stringify(d).slice(0, 150)
      , 5000);
    }));

    document.getElementById("btn-shift").addEventListener("click", () => withBtn("btn-shift", async () => {
      const r = await fetch(BASE + "/agent/income/income-summary");
      const d = await r.json();
      toast(JSON.stringify(d).slice(0, 250), 5000);
    }));

    document.getElementById("btn-luke").addEventListener("click", () => withBtn("btn-luke", async () => {
      const r = await fetch(BASE + "/agent/health/luke-status");
      const d = await r.json();
      toast((d.assessment || d.reply || JSON.stringify(d)).slice(0, 250), 6000);
    }));

    // ── LOOK ──────────────────────────────────────────────

    document.getElementById("look-btn").addEventListener("click", () => look());

    // ── STAGED TRADE ──────────────────────────────────────

    const pendingTrade = document.getElementById("pending-trade");
    const executeBtn   = document.getElementById("execute-btn");
    const skipBtn      = document.getElementById("skip-btn");
    let countdownInterval = null;

    function showPending(data) {
      const s = data.signal;
      const ticker = s.ticker || "MNQ";
      document.getElementById("pt-signal").textContent =
        s.direction + " " + ticker + "  ·  E:" + s.entry + "  S:" + s.stop + "  T:" + s.target;
      document.getElementById("pt-meta").textContent   = "Risk: $" + data.risk_dollars + "  ·  R:R " + data.rr + ":1";
      document.getElementById("pt-reason").textContent = s.reason || "";
      document.getElementById("lbl-target").textContent = "T " + s.target;
      document.getElementById("lbl-entry").textContent  = "E " + s.entry;
      document.getElementById("lbl-stop").textContent   = "S " + s.stop;
      pendingTrade.classList.add("visible");
      loadTVWidget(ticker);
      startCountdown(data.seconds_left);
    }

    function hidePending() {
      pendingTrade.classList.remove("visible");
      if (countdownInterval) { clearInterval(countdownInterval); countdownInterval = null; }
      document.getElementById("pt-chart-inner").innerHTML = "";
    }

    function loadTVWidget(ticker) {
      const container = document.getElementById("pt-chart-inner");
      container.innerHTML = "";
      const wrapper = document.createElement("div");
      wrapper.className = "tradingview-widget-container";
      const inner = document.createElement("div");
      inner.className = "tradingview-widget-container__widget";
      wrapper.appendChild(inner);
      const script = document.createElement("script");
      script.type = "text/javascript";
      script.src = "https://s3.tradingview.com/external-embedding/embed-widget-advanced-chart.js";
      script.async = true;
      script.text = JSON.stringify({
        autosize: false, width: "100%", height: 162,
        symbol: ticker === "MES" ? "CME_MINI:MES1!" : "CME_MINI:MNQ1!",
        interval: "5", timezone: "America/New_York", theme: "dark", style: "1", locale: "en",
        hide_top_toolbar: true, hide_legend: true, allow_symbol_change: false,
        calendar: false, hide_volume: true, support_host: "https://www.tradingview.com"
      });
      wrapper.appendChild(script);
      container.appendChild(wrapper);
    }

    function startCountdown(seconds) {
      if (countdownInterval) clearInterval(countdownInterval);
      const total = 300;
      let s = seconds;
      const textEl = document.getElementById("pt-countdown-text");
      const ringEl = document.getElementById("pt-ring");
      function tick() {
        if (s <= 0) { hidePending(); return; }
        textEl.textContent = Math.floor(s / 60) + ":" + (s % 60).toString().padStart(2, "0");
        ringEl.style.strokeDasharray = ((s / total) * 100) + " 100";
        ringEl.style.stroke = s < 60 ? "#f87171" : "#e2b96a";
        s--;
      }
      tick();
      countdownInterval = setInterval(tick, 1000);
    }

    async function checkPendingSignal() {
      try {
        const r = await fetch(BASE + "/agent/autonomous/pending");
        const d = await r.json();
        if (d.pending) showPending(d);
        else hidePending();
      } catch {}
    }
    checkPendingSignal();
    setInterval(checkPendingSignal, 15000);

    executeBtn.addEventListener("click", async () => {
      executeBtn.disabled = true; executeBtn.textContent = "...";
      try {
        const r = await fetch(BASE + "/agent/autonomous/execute-staged", { method: "POST", headers: { "Content-Type": "application/json" }, body: "{}" });
        const d = await r.json();
        hidePending();
        if (d.executed === false) addMessage("assistant", "Execute failed: " + d.reason, "alert");
      } catch { addMessage("assistant", "Execute error.", "alert"); }
      executeBtn.disabled = false; executeBtn.textContent = "EXECUTE";
    });

    skipBtn.addEventListener("click", async () => {
      try { await fetch(BASE + "/agent/autonomous/skip-staged", { method: "POST", headers: { "Content-Type": "application/json" }, body: "{}" }); } catch {}
      hidePending();
    });

    document.addEventListener("keydown", e => {
      if (!pendingTrade.classList.contains("visible")) return;
      if ((e.key === "e" || e.key === "E") && !executeBtn.disabled) executeBtn.click();
      if (e.key === "s" || e.key === "S") skipBtn.click();
    });

    // ── WEBSOCKET ─────────────────────────────────────────

    ws.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data);
        if (data.type === "staged_trade")   showPending(data);
        else if (data.type === "status_update") updateChips(data);
        else if (data.type === "notification") {
          addMessage("assistant", data.message, "alert");
          if (/02B|KILL|PAPER|LIVE|CLOSED/.test(data.message)) syncStatus();
        }
      } catch {}
    };

    // ── STATE INDICATOR ───────────────────────────────────

    function updateStateIndicator(state) {
      if (!state) return;
      const el = document.getElementById("ribbon-state");
      el.className = state === "regulated" ? "" : state;
      const labels = { regulated: "ONLINE", stressed: "STRESSED", spiraling: "SPIRALING", rule_break: "RULE BREAK" };
      el.textContent = labels[state] || "ONLINE";
    }

    // ── MESSAGES ─────────────────────────────────────────

    function addMessage(role, text, type) {
      const wrapper = document.createElement("div");
      wrapper.className = "wrapper " + (role === "user" ? "user" : "jarvis");
      if (role !== "user") {
        const label = document.createElement("div");
        label.className = "label";
        label.textContent = type === "vision" ? "JARVIS — VISION" : type === "alert" ? "JARVIS — ALERT" : "JARVIS";
        wrapper.appendChild(label);
      }
      const msg = document.createElement("div");
      msg.className = "msg " + (role === "user" ? "user" : type === "vision" ? "vision" : type === "alert" ? "alert" : "jarvis");
      msg.textContent = text;
      wrapper.appendChild(msg);
      messages.appendChild(wrapper);
      messages.scrollTop = messages.scrollHeight;
    }

    function addImageMessage(dataUrl) {
      const wrapper = document.createElement("div");
      wrapper.className = "wrapper user";
      const msg = document.createElement("div");
      msg.className = "msg user";
      const img = document.createElement("img");
      img.src = dataUrl;
      msg.appendChild(img);
      wrapper.appendChild(msg);
      messages.appendChild(wrapper);
      messages.scrollTop = messages.scrollHeight;
    }

    function showThinking(text) {
      const div = document.createElement("div");
      div.className = "thinking"; div.id = "thinking";
      div.textContent = text || "THINKING...";
      messages.appendChild(div);
      messages.scrollTop = messages.scrollHeight;
    }

    function hideThinking() {
      const t = document.getElementById("thinking");
      if (t) t.remove();
    }

    // ── IMAGE PASTE / DROP ────────────────────────────────

    async function handleImageBlob(blob, mimeType) {
      const reader = new FileReader();
      reader.onload = async (evt) => {
        const dataUrl = evt.target.result;
        const base64  = dataUrl.split(",")[1];
        addImageMessage(dataUrl);
        const question = input.value.trim() || "What's in this image?";
        input.value = "";
        showThinking("ANALYZING...");
        sendBtn.disabled = true;
        try {
          const r = await fetch(BASE + "/see-image", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ image: base64, mime_type: mimeType, question })
          });
          const d = await r.json();
          hideThinking();
          addMessage("assistant", d.reply || d.error || "No response.", "vision");
        } catch {
          hideThinking();
          addMessage("assistant", "Image analysis failed.");
        }
        sendBtn.disabled = false;
        input.focus();
      };
      reader.readAsDataURL(blob);
    }

    document.addEventListener("paste", (e) => {
      const items = Array.from(e.clipboardData?.items || []);
      const imageItem = items.find(item => item.type.startsWith("image/"));
      if (!imageItem) return;
      e.preventDefault();
      handleImageBlob(imageItem.getAsFile(), imageItem.type);
    });

    let dragDepth = 0;
    const dragOverlay = document.getElementById("drag-overlay");
    document.addEventListener("dragenter", (e) => {
      if (Array.from(e.dataTransfer?.items || []).some(i => i.kind === "file" && i.type.startsWith("image/"))) {
        dragDepth++;
        dragOverlay.classList.add("show");
      }
    });
    document.addEventListener("dragleave", () => {
      dragDepth--;
      if (dragDepth <= 0) { dragDepth = 0; dragOverlay.classList.remove("show"); }
    });
    document.addEventListener("dragover", (e) => e.preventDefault());
    document.addEventListener("drop", (e) => {
      e.preventDefault();
      dragDepth = 0;
      dragOverlay.classList.remove("show");
      const file = e.dataTransfer?.files[0];
      if (file && file.type.startsWith("image/")) handleImageBlob(file, file.type);
    });

    // ── CHAT ─────────────────────────────────────────────

    async function look(question) {
      showThinking("LOOKING...");
      sendBtn.disabled = true;
      try {
        const r = await fetch(BASE + "/see", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ question: question || "What's on this screen? Be brief." }) });
        const d = await r.json();
        hideThinking();
        addMessage("assistant", d.reply, "vision");
      } catch {
        hideThinking();
        addMessage("assistant", "Vision error.");
      }
      sendBtn.disabled = false;
      input.focus();
    }

    async function doAction(text) {
      showThinking("DOING...");
      sendBtn.disabled = true;
      const parts = text.split(" ");
      try {
        const r = await fetch(BASE + "/do", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ action: parts[0].toLowerCase(), value: parts.slice(1).join(" ") }) });
        const d = await r.json();
        hideThinking();
        addMessage("assistant", d.reply || "Done.", "vision");
      } catch {
        hideThinking();
        addMessage("assistant", "Action error.");
      }
      sendBtn.disabled = false;
      input.focus();
    }

    async function chat(text) {
      showThinking("THINKING...");
      sendBtn.disabled = true;
      try {
        const r = await fetch(BASE + "/chat", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ message: text, history }) });
        const d = await r.json();
        hideThinking();
        addMessage("assistant", d.reply);
        if (d.state) updateStateIndicator(d.state);
        history = d.history;
      } catch {
        hideThinking();
        addMessage("assistant", "Connection error.");
      }
      sendBtn.disabled = false;
      input.focus();
    }

    async function send() {
      const text = input.value.trim();
      if (!text) return;
      input.value = "";
      addMessage("user", text);
      if (/^(open|type|click|scroll|press)\s/i.test(text))      await doAction(text);
      else if (/(screen|look|what's open|what do you see)/i.test(text)) await look(text);
      else await chat(text);
    }

    sendBtn.addEventListener("click", send);
    input.addEventListener("keydown", e => { if (e.key === "Enter") send(); });
  </script>
</body>
</html>
